import React, { useState } from 'react';
import { Save, Trophy, Scale, Ruler, Calendar, Star, Unlock } from 'lucide-react';

export default function Profile({ user }) {
  const [isEditing, setIsEditing] = useState(false);
  const [form, setForm] = useState({
    username: user?.username || 'User',
    email: user?.email || 'user@example.com',
    height: user?.height || 170,
    weight: user?.weight || 70,
    age: user?.age || 25,
    weeklyGoal: user?.weeklyGoal || 4
  });

  // BMI Calculation
  const heightM = form.height / 100;
  const bmi = form.weight && heightM ? (form.weight / (heightM * heightM)).toFixed(1) : 0;
  
  const getBMICategory = (b) => {
    if (b < 18.5) return { label: 'Underweight', color: '#f59e0b' };
    if (b < 24.9) return { label: 'Normal', color: '#22c55e' };
    if (b < 29.9) return { label: 'Overweight', color: '#f59e0b' };
    return { label: 'Obese', color: '#ef4444' };
  };

  const bmiCat = getBMICategory(parseFloat(bmi));

  const handleSave = () => {
    setIsEditing(false);
    // You can add API call here to update user profile
  };

  const allBadges = [
    { name: 'First Workout', icon: '🎯', earned: user?.badges?.includes('First Workout') },
    { name: '7 Day Streak', icon: '🔥', earned: user?.badges?.includes('7 Day Streak') },
    { name: '30 Day Streak', icon: '💪', earned: user?.badges?.includes('30 Day Streak') },
    { name: '50 Club', icon: '🏆', earned: user?.badges?.includes('50 Club') },
    { name: 'Calorie Crusher', icon: '⚡', earned: user?.badges?.includes('Calorie Crusher') },
    { name: 'Early Bird', icon: '🌅', earned: user?.badges?.includes('Early Bird') },
  ];

  return (
    <div className="main-content">
      <h1 className="page-title">Profile</h1>
      
      <div className="grid-2">
        {/* Profile Info Card */}
        <div className="card">
          <div className="p-header">
            <div className="p-avatar">{form.username?.charAt(0)?.toUpperCase() || 'U'}</div>
            <div className="p-info">
              <h3>{form.username}</h3>
              <p style={{color: '#aaa'}}>{form.email}</p>
            </div>
            <button 
              className="btn" 
              style={{width: 'auto', marginLeft: 'auto', padding: '10px 16px', background: isEditing ? '#22c55e' : '#6366f1'}}
              onClick={() => isEditing ? handleSave() : setIsEditing(true)}
            >
              {isEditing ? <><Save size={16} /> Save</> : <><Unlock size={16} /> Edit</>}
            </button>
          </div>

          <div className="p-stats">
            <div className="p-stat">
              <Scale size={18} />
              <div>
                <label>Weight</label>
                {isEditing ? (
                  <input
                    type="number"
                    className="form-input"
                    value={form.weight}
                    onChange={(e) => setForm({...form, weight: parseFloat(e.target.value)})}
                  />
                ) : (
                  <span>{form.weight} kg</span>
                )}
              </div>
            </div>
            <div className="p-stat">
              <Ruler size={18} />
              <div>
                <label>Height</label>
                {isEditing ? (
                  <input
                    type="number"
                    className="form-input"
                    value={form.height}
                    onChange={(e) => setForm({...form, height: parseFloat(e.target.value)})}
                  />
                ) : (
                  <span>{form.height} cm</span>
                )}
              </div>
            </div>
            <div className="p-stat">
              <Calendar size={18} />
              <div>
                <label>Age</label>
                {isEditing ? (
                  <input
                    type="number"
                    className="form-input"
                    value={form.age}
                    onChange={(e) => setForm({...form, age: parseInt(e.target.value)})}
                  />
                ) : (
                  <span>{form.age} yrs</span>
                )}
              </div>
            </div>
            <div className="p-stat">
              <Star size={18} />
              <div>
                <label>Goal</label>
                {isEditing ? (
                  <input
                    type="number"
                    className="form-input"
                    value={form.weeklyGoal}
                    onChange={(e) => setForm({...form, weeklyGoal: parseInt(e.target.value)})}
                  />
                ) : (
                  <span>{form.weeklyGoal}/week</span>
                )}
              </div>
            </div>
          </div>

          {/* BMI Calculator */}
          <div style={{marginTop: '24px'}}>
            <h4 style={{marginBottom: '16px', display: 'flex', alignItems: 'center', gap: '8px'}}>
              <Scale size={18} /> BMI Calculator
            </h4>
            <div className="bmi-box">
              <div style={{flex: 1}}>
                <div 
                  className="bmi-result" 
                  style={{
                    background: `${bmiCat.color}20`, 
                    borderColor: bmiCat.color,
                    padding: '16px 24px',
                    borderRadius: '12px',
                    border: '2px solid',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center'
                  }}
                >
                  <span style={{color: bmiCat.color, fontSize: '32px', fontWeight: '700'}}>{bmi}</span>
                  <span style={{color: bmiCat.color, fontSize: '14px'}}>{bmiCat.label}</span>
                </div>
              </div>
              {isEditing && (
                <div style={{flex: 1}}>
                  <input
                    type="range"
                    min="40"
                    max="150"
                    value={form.weight}
                    onChange={(e) => setForm({...form, weight: parseFloat(e.target.value)})}
                    style={{width: '100%'}}
                  />
                  <div style={{display: 'flex', justifyContent: 'space-between', fontSize: '12px', color: '#666', marginTop: '4px'}}>
                    <span>40 kg</span>
                    <span>150 kg</span>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Achievements Card */}
        <div className="card">
          <h3 style={{display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '20px'}}>
            <Trophy size={20} /> Achievements
          </h3>
          
          <div className="user-stats-row">
            <div className="u-stat">
              <span className="u-stat-num">{user?.totalWorkouts || 0}</span>
              <span className="u-stat-label">Total</span>
            </div>
            <div className="u-stat">
              <span className="u-stat-num">{user?.currentStreak || 0}</span>
              <span className="u-stat-label">Streak</span>
            </div>
            <div className="u-stat">
              <span className="u-stat-num">{user?.longestStreak || 0}</span>
              <span className="u-stat-label">Best</span>
            </div>
            <div className="u-stat">
              <span className="u-stat-num">{Math.round((user?.totalCaloriesBurned || 0) / 1000)}k</span>
              <span className="u-stat-label">Calories</span>
            </div>
          </div>

          <h4 style={{marginBottom: '12px', color: '#aaa'}}>Badges</h4>
          <div className="badge-list">
            {allBadges.map((badge, i) => (
              <div key={i} className={`badge-item ${badge.earned ? '' : 'locked'}`}>
                <span style={{fontSize: '24px'}}>{badge.earned ? badge.icon : '🔒'}</span>
                <div>
                  <div className="badge-name" style={{color: badge.earned ? '#fff' : '#666'}}>{badge.name}</div>
                  <div style={{fontSize: '12px', color: '#666'}}>
                    {badge.earned ? 'Earned!' : 'Not yet earned'}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
